        self$output_size <- output_size
        if (!is.null(output_ratio)) {
            output_ratio <- nn_util_pair(output_ratio)
        }
        self$output_ratio <- output_ratio
        if (is.null(output_ratio) && is.null(output_size)) {
            value_error("both output_size and output_ratio are NULL")
        }
        if (!is.null(output_ratio) && !is.null(output_size)) {
            value_error("both output_size and output_ratio are not NULL")
        }
        if (!is.null(output_ratio)) {
            if (any(output_ratio > 1 | output_ratio < 0)) {
                value_error("output_ratio must be between 0 and 1.")
            }
        }
    },
    forward = function(input) {
        nnf_fractional_max_pool2d(input, self$kernel_size, self$output_size, self$output_ratio, self$return_indices, random_samples = self$random_samples)
    }
  )(kernel_size, output_size, output_ratio, return_indices)
}

