#' @export
nn_multihead_attention <- function(embed_dim, num_heads, dropout = 0, bias = TRUE, add_bias_kv = FALSE, add_zero_attn = FALSE, kdim = NULL, vdim = NULL, batch_first = FALSE) {
  nn_module("nn_multihead_attention",
    initialize = function(embed_dim, num_heads, dropout = 0, bias = TRUE, add_bias_kv = FALSE, add_zero_attn = FALSE, kdim = NULL, vdim = NULL, batch_first = FALSE) {
        self$embed_dim <- embed_dim
        if (!is.null(kdim)) {
            self$kdim <- kdim
        }
        else {
            self$kdim <- embed_dim
        }
        if (!is.null(vdim)) {
            self$vdim <- vdim
        }
        else {
            self$vdim <- embed_dim
        }
        self$qkv_same_embed_dim_ <- self$kdim == embed_dim && self$vdim == embed_dim
        self$num_heads <- num_heads
        self$dropout <- dropout
        self$head_dim <- embed_dim%/%num_heads
        if ((self$head_dim * num_heads) != self$embed_dim) {
            value_error("embed_dim must be divisible by num_heads")
        }
        if (!self$qkv_same_embed_dim_) {
            self$q_proj_weight <- nn_parameter(torch_empty(embed_dim, embed_dim))
            self$k_proj_weight <- nn_parameter(torch_empty(embed_dim, self$kdim))
            self$v_proj_weight <- nn_parameter(torch_empty(embed_dim, self$vdim))
            self$register_parameter("in_proj_weight", NULL)
        }
        else {
            self$in_proj_weight <- nn_parameter(torch_empty(3 * embed_dim, embed_dim))
            self$register_parameter("q_proj_weight", NULL)
            self$register_parameter("k_proj_weight", NULL)
            self$register_parameter("v_proj_weight", NULL)
        }
        if (bias) {
            self$in_proj_bias <- nn_parameter(torch_empty(3 * embed_dim))
        }
        else {
            self$register_parameter("in_proj_bias", NULL)
        }
        self$out_proj <- nn_linear(embed_dim, embed_dim, bias = bias)
        if (add_bias_kv) {
            self$bias_k <- nn_parameter(torch_empty(1, 1, embed_dim))
            self$bias_v <- nn_parameter(torch_empty(1, 1, embed_dim))
        }
        else {
            self$bias_k <- NULL
            self$bias_v <- NULL
        }
        self$add_zero_attn <- add_zero_attn
        self$batch_first <- batch_first
        self$reset_parameters()
    },
    forward = function(query, key, value, key_padding_mask = NULL, need_weights = TRUE, attn_mask = NULL, avg_weights = TRUE) {
        if (!self$qkv_same_embed_dim_) {
            nnf_multi_head_attention_forward(query, key, value, self$embed_dim, self$num_heads, self$in_proj_weight, self$in_proj_bias, self$bias_k, self$bias_v, self$add_zero_attn, self$dropout, self$out_proj$weight, self$out_proj$bias, training = self$training, key_padding_mask = key_padding_mask, need_weights = need_weights, attn_mask = attn_mask, use_separate_proj_weight = TRUE, q_proj_weight = self$q_proj_weight, k_proj_weight = self$k_proj_weight, v_proj_weight = self$v_proj_weight, batch_first = self$batch_first)
        }
        else {
            nnf_multi_head_attention_forward(query, key, value, self$embed_dim, self$num_heads, self$in_proj_weight, self$in_proj_bias, self$bias_k, self$bias_v, self$add_zero_attn, self$dropout, self$out_proj$weight, self$out_proj$bias, training = self$training, key_padding_mask = key_padding_mask, need_weights = need_weights, attn_mask = attn_mask, avg_weights = avg_weights, batch_first = self$batch_first)
        }
    }
  )(embed_dim, num_heads, dropout, bias, add_bias_kv, add_zero_attn, kdim, vdim, batch_first)
}

