#' @export
nn_norm_base_ <- function(num_features, eps = 1e-05, momentum = 0.1, affine = TRUE, track_running_stats = TRUE) {
  nn_module("nn_norm_base_",
    initialize = function(num_features, eps = 1e-05, momentum = 0.1, affine = TRUE, track_running_stats = TRUE) {
        self$num_features <- num_features
        self$eps <- eps
        self$momentum <- momentum
        self$affine <- affine
        self$track_running_stats <- track_running_stats
        if (self$affine) {
            self$weight <- nn_parameter(torch_empty(num_features))
            self$bias <- nn_parameter(torch_empty(num_features))
        }
        else {
            self$weight <- NULL
            self$bias <- NULL
        }
        if (self$track_running_stats) {
            self$running_mean <- nn_buffer(torch_zeros(num_features))
            self$running_var <- nn_buffer(torch_ones(num_features))
            self$num_batches_tracked <- nn_buffer(torch_tensor(0, dtype = torch_long()))
        }
        else {
            self$running_mean <- NULL
            self$running_var <- NULL
            self$num_batches_tracked <- NULL
        }
        self$reset_parameters()
    },
    forward = function()   stop("forward not defined")
  )(num_features, eps, momentum, affine, track_running_stats)
}

