#' @export
nn_rnn_base <- function(mode, input_size, hidden_size, num_layers = 1, bias = TRUE, batch_first = FALSE, dropout = 0, bidirectional = FALSE) {
  nn_module("nn_rnn_base",
    initialize = function(mode, input_size, hidden_size, num_layers = 1, bias = TRUE, batch_first = FALSE, dropout = 0, bidirectional = FALSE) {
        self$mode <- mode
        self$input_size <- input_size
        self$hidden_size <- hidden_size
        self$num_layers <- num_layers
        self$bias <- bias
        self$batch_first <- batch_first
        self$dropout <- dropout
        self$bidirectional <- bidirectional
        self$proj_size <- 0
        if (bidirectional) {
            num_directions <- 2
        }
        else {
            num_directions <- 1
        }
        if (dropout > 0 && num_layers == 1) {
            warn("dropout option adds dropout after all but last ", "recurrent layer, so non-zero dropout expects ", "num_layers greater than 1, but got dropout={dropout} and ", "num_layers={num_layers}")
        }
        if (mode == "LSTM") {
            gate_size <- 4 * hidden_size
        }
        else if (mode == "GRU") {
            gate_size <- 3 * hidden_size
        }
        else if (mode == "RNN_TANH") {
            gate_size <- hidden_size
        }
        else if (mode == "RNN_RELU") {
            gate_size <- hidden_size
        }
        else {
            value_error("Unrecognized RNN mode: {mode}")
        }
        self$flat_weights_names_ <- list()
        self$all_weights_ <- list()
        for (layer in seq_len(num_layers)) {
            for (direction in seq_len(num_directions)) {
                if (layer == 1) {
                    layer_input_size <- input_size
                }
                else {
                    layer_input_size <- hidden_size * num_directions
                }
                w_ih <- nn_parameter(torch_empty(gate_size, layer_input_size))
                w_hh <- nn_parameter(torch_empty(gate_size, hidden_size))
                b_ih <- nn_parameter(torch_empty(gate_size))
                b_hh <- nn_parameter(torch_empty(gate_size))
                layer_params <- list(w_ih, w_hh, b_ih, b_hh)
                if (direction == 2) {
                    suffix <- "_reverse"
                }
                else {
                    suffix <- ""
                }
                param_names <- c(glue::glue("weight_ih_l{layer}{suffix}"), glue::glue("weight_hh_l{layer}{suffix}"))
                if (bias) {
                    param_names <- c(param_names, c(glue::glue("bias_ih_l{layer}{suffix}"), glue::glue("bias_hh_l{layer}{suffix}")))
                }
                for (i in seq_along(param_names)) {
                    self[[param_names[i]]] <- layer_params[[i]]
                }
                self$flat_weight_names_ <- c(self$flat_weight_names_, param_names)
                self$all_weights_ <- c(self$all_weights_, param_names)
            }
        }
        self$flat_weights_ <- lapply(self$flat_weight_names_, function(wn) {
            self[[wn]]
        })
        self$flatten_parameters()
        self$reset_parameters()
    },
    forward = function(input, hx = NULL) {
        is_packed <- is_packed_sequence(input)
        if (is_packed) {
            batch_sizes <- input$batch_sizes
            sorted_indices <- input$sorted_indices
            unsorted_indices <- input$unsorted_indices
            max_batch_size <- as_array(batch_sizes[1]$to(dtype = torch_int()))
            input <- input$data
        }
        else {
            batch_sizes <- NULL
            if (self$batch_first) {
                max_batch_size <- input$size(1)
            }
            else {
                max_batch_size <- input$size(2)
            }
            sorted_indices <- NULL
            unsorted_indices <- NULL
        }
        if (is.null(hx)) {
            num_directions <- ifelse(self$bidirectional, 2, 1)
            hx <- torch_zeros(self$num_layers * num_directions, max_batch_size, self$hidden_size, dtype = input$dtype, device = input$device)
            if (self$mode == "LSTM") {
                hx <- list(hx, hx)
            }
        }
        else {
            hx <- self$permute_hidden(hx, sorted_indices)
        }
        impl_ <- rnn_impls_[[self$mode]]
        if (is.null(batch_sizes)) {
            result <- impl_(input = input, hx = hx, params = self$flat_weights_, has_biases = self$bias, num_layers = self$num_layers, dropout = self$dropout, train = self$training, bidirectional = self$bidirectional, batch_first = self$batch_first)
        }
        else {
            result <- impl_(data = input, hx = hx, batch_sizes = batch_sizes, params = self$flat_weights_, has_biases = self$bias, num_layers = self$num_layers, dropout = self$dropout, train = self$training, bidirectional = self$bidirectional)
        }
        output <- result[[1]]
        hidden <- result[-1]
        if (length(hidden) == 1) {
            hidden <- hidden[[1]]
        }
        if (is_packed) {
            output <- new_packed_sequence(output, batch_sizes, sorted_indices, unsorted_indices)
        }
        list(output, self$permute_hidden(hidden, unsorted_indices))
    }
  )(mode, input_size, hidden_size, num_layers, bias, batch_first, dropout, bidirectional)
}

#' @export
nn_transformer_encoder <- function(encoder_layer, num_layers, norm = NULL) {
  nn_module("nn_transformer_encoder",
    initialize = function(encoder_layer, num_layers, norm = NULL) {
        if (!is_nn_module(encoder_layer)) {
            value_error("`encoder_layer` must be an `nn_module` (transformer encoder layer instance).")
        }
        self$num_layers <- num_layers
        self$layers <- nn_module_list(lapply(seq_len(num_layers), function(i) {
            clone_module(encoder_layer, deep = TRUE)
        }))
        self$norm <- norm
    },
    forward = function(src, mask = NULL, src_key_padding_mask = NULL, is_causal = FALSE) {
        output <- src
        for (i in seq_along(self$layers)) {
            output <- self$layers[[i]](output, src_mask = mask, src_key_padding_mask = src_key_padding_mask, is_causal = is_causal)
        }
        if (!is.null(self$norm)) {
            output <- self$norm(output)
        }
        return(output)
    }
  )(encoder_layer, num_layers, norm)
}

#' @export
nn_transformer_encoder_layer <- function(d_model, nhead, dim_feedforward = 2048, dropout = 0.1, activation = "relu", layer_norm_eps = 1e-05, batch_first = FALSE, norm_first = FALSE, bias = TRUE) {
  nn_module("nn_transformer_encoder_layer",
    initialize = function(d_model, nhead, dim_feedforward = 2048, dropout = 0.1, activation = "relu", layer_norm_eps = 1e-05, batch_first = FALSE, norm_first = FALSE, bias = TRUE) {
        self$norm_first <- norm_first
        self$self_attn <- nn_multihead_attention(embed_dim = d_model, num_heads = nhead, dropout = dropout, bias = bias, batch_first = batch_first)
        self$linear1 <- nn_linear(d_model, dim_feedforward, bias = bias)
        self$linear2 <- nn_linear(dim_feedforward, d_model, bias = bias)
        self$dropout <- nn_dropout(dropout)
        self$dropout1 <- nn_dropout(dropout)
        self$dropout2 <- nn_dropout(dropout)
        self$norm1 <- nn_layer_norm(normalized_shape = d_model, eps = layer_norm_eps, elementwise_affine = bias)
        self$norm2 <- nn_layer_norm(normalized_shape = d_model, eps = layer_norm_eps, elementwise_affine = bias)
        if (is.character(activation)) {
            act_name <- tolower(activation)
            if (act_name == "relu") {
                self$activation <- function(x) nnf_relu(x)
                self$activation_relu_or_gelu <- 1
            }
            else if (act_name == "gelu") {
                self$activation <- function(x) nnf_gelu(x)
                self$activation_relu_or_gelu <- 2
            }
            else {
                value_error("Unsupported activation string: {activation}. Use 'relu', 'gelu', or a callable function.")
            }
        }
        else if (is.function(activation)) {
            self$activation <- activation
            self$activation_relu_or_gelu <- 0
        }
        else {
            value_error("activation must be a string ('relu' or 'gelu') or a function.")
        }
    },
    forward = function(src, src_mask = NULL, src_key_padding_mask = NULL, is_causal = FALSE) {
        if (!is.null(src_mask) && is_causal) {
            value_error("Explicit src_mask should not be set when is_causal=TRUE. Use one or the other.")
        }
        attn_mask_eff <- src_mask
        if (is_causal) {
            if (self$self_attn$batch_first) {
                L <- dim(src)[2]
            }
            else {
                L <- dim(src)[1]
            }
            attn_mask_eff <- torch_ones(c(L, L), dtype = torch_bool())
            attn_mask_eff <- attn_mask_eff$triu(diagonal = 1)
        }
        if (self$norm_first) {
            norm_src <- self$norm1(src)
            attn_out <- self$self_attn(norm_src, norm_src, norm_src, attn_mask = attn_mask_eff, key_padding_mask = src_key_padding_mask, need_weights = FALSE)[[1]]
            src2 <- src + self$dropout1(attn_out)
            norm_src2 <- self$norm2(src2)
            ff_out <- self$linear2(self$dropout(self$activation(self$linear1(norm_src2))))
            out <- src2 + self$dropout2(ff_out)
        }
        else {
            attn_out <- self$self_attn(src, src, src, attn_mask = attn_mask_eff, key_padding_mask = src_key_padding_mask, need_weights = FALSE)[[1]]
            src2 <- src + self$dropout1(attn_out)
            out1 <- self$norm1(src2)
            ff_out <- self$linear2(self$dropout(self$activation(self$linear1(out1))))
            out2 <- out1 + self$dropout2(ff_out)
            out <- self$norm2(out2)
        }
        return(out)
    }
  )(d_model, nhead, dim_feedforward, dropout, activation, layer_norm_eps, batch_first, norm_first, bias)
}

#' @export
nn_triplet_margin_with_distance_loss <- function(distance_function = NULL, margin = 1, swap = FALSE, reduction = "mean") {
