            self$distance_function <- distance_function
        }
        self$margin <- margin
        self$swap <- swap
    },
    forward = function(anchor, positive, negative) {
        nnf_triplet_margin_with_distance_loss(anchor, positive, negative, distance_function = self$distance_function, margin = self$margin, swap = self$swap, reduction = self$reduction)
    }
  )(distance_function, margin, swap, reduction)
}

